          <div className="text-4xl mb-2">{archetype.emoji}</div>
          <p className="text-xs text-zinc-500 uppercase tracking-widest mb-1">Music Personality</p>
          <h3
            className={`text-2xl font-bold bg-gradient-to-r bg-clip-text text-transparent ${archetype.gradient}`}
            style={{ fontFamily: "var(--font-righteous)" }}
          >
            {archetype.name}
          </h3>
        </div>

        {/* Top artists line */}
        <div className="text-center">
          <p className="text-xs text-zinc-600 mb-1">Featuring</p>
          <p className="text-sm text-zinc-400">
            {topArtists.slice(0, 3).map((a) => a.name).join(" · ")}
          </p>
        </div>

        {/* Trait pills */}
        <div className="flex flex-wrap justify-center gap-1.5">
          {Object.entries(traits).map(([key, value]) => {
            const labels: Record<string, string> = {
              energy: "⚡ Energy",
              emotion: "💜 Emotion",
              curiosity: "🔍 Curious",
              nostalgia: "📻 Nostalgic",
              obscurity: "🪐 Obscure",
              consistency: "🎯 Loyal",
            };
            return (
              <span
                key={key}
                className="px-2.5 py-1 rounded-full text-xs font-medium bg-white/5 border border-white/10 text-zinc-300"
              >
                {labels[key] || key} {value}%
              </span>
            );
          })}
        </div>

        {/* Stats row */}
        <div className="grid grid-cols-4 gap-2 text-center">
          {[
            { label: "Energy", value: `${stats.avgEnergy}%` },
            { label: "Mood", value: `${stats.avgValence}%` },
            { label: "BPM", value: stats.avgTempo },
            { label: "Era", value: stats.topDecade },
          ].map((s) => (
            <div key={s.label}>
              <div className="text-base font-bold text-white">{s.value}</div>
              <div className="text-[10px] text-zinc-500">{s.label}</div>
            </div>
